import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

export default function ImageCardXFlow({ imgObj, onCardClick }) {
  const [imgIndex, setImgIndex] = useState(0);
  const [showFullText, setShowFullText] = useState(false);
  const navigate = useNavigate()

  const prevImage = (e) => {
    e.stopPropagation();
    setImgIndex((prev) => (prev === 0 ? imgObj.images.length - 1 : prev - 1));
  };

  const nextImage = (e) => {
    e.stopPropagation();
    setImgIndex((prev) => (prev === imgObj.images.length - 1 ? 0 : prev + 1));
  };

  const selectImage = (e, idx) => {
    e.stopPropagation();
    setImgIndex(idx);
  };

  // Truncation utility logic: Cut roughly at half lengths if name crosses 32 chars
  const isTooLong = imgObj.name.length > 32;
  const processNameDisplay = () => {
    if (!isTooLong || showFullText) return imgObj.name;
    return `${imgObj.name.substring(0, 24)}...`;
  };
  
  const handleProductNavigation = (productId) => {
    // Navigates passing selections via location query parameters
    navigate(`/product?city=Madurai&company=Gv-Solutions&product=${productId}`);
  };


  return (
    <div className="profile-card">
      <h2 className="section-card-heading">
        Product Listings{" "}
        <span>
          <i className="fa-solid fa-arrow-right"></i>
        </span>
      </h2>
      <div className="product-horizontal-scroll-axis-track">
        {BACKEND_COMPANY_DATA.products.map((product) => (
          <div
            className="product-listing-card"
            onClick={() => onCardClick(imgObj.id)}
          >
            <div className="product-card-image-box">
              <img src={imgObj.images[imgIndex]} alt={imgObj.name} />
              {imgObj.images.length > 1 && (
                <>
                  <button
                    className="img-nav-btn left-arrow"
                    onClick={prevImage}
                  >
                    ‹
                  </button>
                  <button
                    className="img-nav-btn right-arrow"
                    onClick={nextImage}
                  >
                    ›
                  </button>
                </>
              )}
              <div className="product-dots-indicator-container">
                {imgObj.images.map((_, i) => (
                  <span
                    key={i}
                    className={`dot-indicator${i === imgIndex ? " active" : ""}`}
                    onClick={(e) => selectImage(e, i)}
                  />
                ))}
              </div>
            </div>
            <div className="product-card-info-box">
              <div className="product-card-title-line">
                <span className="product-name-txt">{processNameDisplay()}</span>
                {isTooLong && (
                  <button
                    className="product-name-more-toggle-btn"
                    onClick={(e) => {
                      e.stopPropagation();
                      setShowFullText(!showFullText);
                    }}
                  >
                    {showFullText ? " less" : " more"}
                  </button>
                )}
              </div>
              <div className="product-card-price-tag">{imgObj.price}</div>
            </div>
          </div>
        ))}
      </div>
      {/* <div className="action-upload-footer-dock">
                    <input type="file" ref={fileRef} hidden accept="image/*" onChange={handleFileChange} />
                    <button className="btn-upload" onClick={handleUploadClick}>
                      <i className="fas fa-cloud-upload-alt"></i> Upload System Imagery Assets
                    </button>
                  </div> */}
    </div>
  );
}
